const data = $json;
const companyData = $('Prepare Company Data').item.json;

const locations = data.locations || [];
const primary = locations.find(l => l.is_primary) || locations[0] || {};
const countryFromAmplemarket = primary.country || '';

return { json: { ...companyData, countryFromAmplemarket } };

const companyData = $('Prepare Company Data').item.json;
const companyName = companyData.companyName || '';
const domain = companyData.domain || '';

const prompt = `You are an expert at identifying the headquarters country of companies.

COMPANY: ${companyName}
DOMAIN: ${domain || 'Not provided'}

Based ONLY on the company name and domain, identify the headquarters country.

SIGNALS:
1. Well-known company recognition (e.g., "Siemens" + siemens.com = Germany)
2. Geographic hints in domain name (e.g., "uk-consulting.com")
3. City/region references in name (e.g., "Berlin Digital GmbH")
4. Legal suffixes: GmbH=Germany/Austria/Switzerland, Ltd=UK, SRL=Italy/Romania, BV=Netherlands, SA=France/Spain, AB=Sweden, AS=Norway/Denmark, Pty=Australia/South Africa, Inc/LLC/Corp=United States

RESPONSE (JSON only, no markdown):
{"country": "<full country name>", "confidence": "HIGH|MEDIUM|LOW"}

HIGH = certain (recognized brand or unambiguous legal suffix)
MEDIUM = strong signals with some ambiguity
LOW = cannot determine confidently

If no idea: {"country": "Unknown", "confidence": "LOW"}`;

return { json: { companyId: companyData.companyId, companyName, domain, prompt } };

const geminiText = ($json?.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
const companyData = $('Prepare Company Data').item.json;

let blindCountry = '';
let blindConfidence = 'LOW';

try {
  const cleaned = geminiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const country = parsed.country || '';
  const confidence = (parsed.confidence || 'LOW').toUpperCase();
  blindConfidence = confidence;

  if ((confidence === 'HIGH' || confidence === 'MEDIUM') &&
      country && country !== 'Unknown') {
    blindCountry = country;
  }
} catch (e) {
  // Parse failed - treat as LOW confidence
}

return { json: { companyId: companyData.companyId, companyName: companyData.companyName, domain: companyData.domain, blindCountry, blindConfidence } };

const companyData = $('Prepare Company Data').item.json;
const companyName = companyData.companyName || '';
const domain = companyData.domain || '';

const prompt = `You are an expert at identifying the headquarters country of companies.
Search the web for information about this company.

COMPANY: ${companyName}
DOMAIN: ${domain || 'Not provided'}

Search for this company's headquarters location, registered office, or primary business address. Check their website, LinkedIn page, and business registries.

RESPONSE (JSON only, no markdown):
{"country": "<full country name in English>"}

RULES:
- Return the headquarters country only (not branch offices)
- Use full English country names (e.g., "United Kingdom", not "UK")
- If you cannot find reliable information: {"country": "Unknown"}`;

return { json: { companyId: companyData.companyId, companyName, domain, prompt } };

const geminiText = ($json?.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
const companyData = $('Prepare Company Data').item.json;

let groundedCountry = '';

try {
  const cleaned = geminiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const country = parsed.country || '';
  if (country && country !== 'Unknown') {
    groundedCountry = country;
  }
} catch (e) {
  const text = geminiText.replace(/[{}"]/g, '').replace(/country\s*:/i, '').trim();
  if (text && text.length < 50 && text !== 'Unknown' && !text.includes('\n')) {
    groundedCountry = text;
  }
}

return { json: { companyId: companyData.companyId, companyName: companyData.companyName, domain: companyData.domain, groundedCountry } };

const d = $input.item.json;
const country = d.countryFromTLD || d.countryFromName || d.countryFromAmplemarket || d.blindCountry || d.groundedCountry || '';

let enrichmentSource = '';
if (d.countryFromTLD) enrichmentSource = 'TLD';
else if (d.countryFromName) enrichmentSource = 'Company name';
else if (d.countryFromAmplemarket) enrichmentSource = 'Amplemarket';
else if (d.blindCountry) enrichmentSource = 'Gemini blind';
else if (d.groundedCountry) enrichmentSource = 'Gemini grounded';

return { json: { companyId: d.companyId, companyName: d.companyName, country, enrichmentSource, resolved: true } };

const items = $json.data || [];
const resolved = items.filter(i => i.resolved);
const unknown = items.filter(i => !i.resolved);

const hubspotBase = 'https://app.hubspot.com/contacts/142047914/company/';

const sourceCounts = {};
for (const c of resolved) {
  sourceCounts[c.enrichmentSource] = (sourceCounts[c.enrichmentSource] || 0) + 1;
}
const sourceStats = Object.entries(sourceCounts).map(([s, n]) => `${s}: ${n}`).join(' \u00b7 ');

let msg = `\ud83c\udf0d *Country Enrichment v2.0 \u2014 Run Complete*\n`;
msg += `*${resolved.length} enriched \u00b7 ${unknown.length} unknown*\n`;
if (sourceStats) msg += `*Sources:* ${sourceStats}\n`;
msg += `\n`;

if (resolved.length > 0) {
  msg += `\u2705 *Enriched*\n`;
  for (const c of resolved) {
    msg += `\u2022 <${hubspotBase + c.companyId}|${c.companyName}> \u2192 *${c.country}* (${c.enrichmentSource})\n`;
  }
}

if (unknown.length > 0) {
  msg += `\n\ud83d\udea9 *Unknown (flagged)*\n`;
  for (const c of unknown) {
    msg += `\u2022 <${hubspotBase + c.companyId}|${c.companyName}>\n`;
  }
}

return { json: { message: msg } };
